using UnityEngine;

public class ParticleSystemExample : MonoBehaviour
{
    public ParticleSystem coinParticles;
    public ParticleSystem explosionParticles;
    public ParticleSystem jumpParticles;
    public ParticleSystem trailParticles;

    void Start()
    {
        // Get all particle systems on the object
        ParticleSystem[] systems = GetComponentsInChildren<ParticleSystem>();
        foreach (ParticleSystem ps in systems)
        {
            Debug.Log("Found particle system: " + ps.name);
        }
    }

    void Update()
    {
        // Test particles with keys
        if (Input.GetKeyDown(KeyCode.Alpha1))
        {
            PlayCoinParticles();
        }
        if (Input.GetKeyDown(KeyCode.Alpha2))
        {
            PlayExplosionParticles();
        }
        if (Input.GetKeyDown(KeyCode.Alpha3))
        {
            PlayJumpParticles();
        }
        if (Input.GetKeyDown(KeyCode.Alpha4))
        {
            ToggleTrailParticles();
        }
    }

    // --- Basic particle control ---
    public void PlayCoinParticles()
    {
        if (coinParticles != null)
        {
            coinParticles.Play();
            Debug.Log("Coin particles playing!");
        }
    }

    public void PlayExplosionParticles()
    {
        if (explosionParticles != null)
        {
            explosionParticles.Play();
            Debug.Log("Explosion particles playing!");
        }
    }

    public void PlayJumpParticles()
    {
        if (jumpParticles != null)
        {
            jumpParticles.Play();
            Debug.Log("Jump particles playing!");
        }
    }

    public void ToggleTrailParticles()
    {
        if (trailParticles != null)
        {
            if (trailParticles.isPlaying)
            {
                trailParticles.Stop();
                Debug.Log("Trail particles stopped!");
            }
            else
            {
                trailParticles.Play();
                Debug.Log("Trail particles started!");
            }
        }
    }

    // --- Particle control methods ---
    public void StopAllParticles()
    {
        if (coinParticles != null) coinParticles.Stop();
        if (explosionParticles != null) explosionParticles.Stop();
        if (jumpParticles != null) jumpParticles.Stop();
        if (trailParticles != null) trailParticles.Stop();
    }

    public void ClearAllParticles()
    {
        if (coinParticles != null) coinParticles.Clear();
        if (explosionParticles != null) explosionParticles.Clear();
        if (jumpParticles != null) jumpParticles.Clear();
        if (trailParticles != null) trailParticles.Clear();
    }

    public void SetParticleColor(ParticleSystem system, Color color)
    {
        if (system != null)
        {
            var main = system.main;
            main.startColor = color;
        }
    }

    public void SetParticleEmission(ParticleSystem system, bool enabled)
    {
        if (system != null)
        {
            var emission = system.emission;
            emission.enabled = enabled;
        }
    }

    public void SetParticleRate(ParticleSystem system, float rate)
    {
        if (system != null)
        {
            var emission = system.emission;
            emission.rateOverTime = rate;
        }
    }
}

